function checkoutSystem(arr)
{
    return new Promise((resolve,reject)=>
                      {
        setTimeout(()=>
                  {
            
             if(arr.length===0)
                       {
                           reject("reject");
                           return;
                       }
            for(let obj of arr)
                {
                    if(obj.price<=0 || obj.price==null ||typeof obj.price !== "number")
                        {
                            reject("reject");
                            return;
                        }
                  
                    
                }
            resolve("yoho");
            
        },1500);
    })
}



checkoutSystem([
  {name: 'Laptop', price: 55000 },
  {name: 'Mouse', price: 450 },
  {name: 'Keyboard', price: 1200 }
])
.then(res=>console.log(res))
.catch(err=>console.log(err));
